// // This comment suggests that the circuit should set q to 1 when both a and b are 1
module top_module (
    input a,
    input b,
    output reg q
);    always @(*) begin
        case ({a, b})
            2'b00: q = 1'b0;
            2'b10: q = 1'b0;
            2'b01: q = 1'b0;
            2'b11: q = 1'b0;
        endcase
    end
endmodule
